import { BarChart3, CircleDollarSign, FileChartColumn, PieChart, ReceiptText, TrendingUp } from "lucide-react";
import { PageHeader } from "@/presentation/components/ui";

const reports = [["Sales Report", "Revenue and invoiced value by period.", TrendingUp], ["Payment Report", "Receipts grouped by status and payment mode.", ReceiptText], ["Outstanding Report", "Pending and overdue balances requiring follow-up.", CircleDollarSign], ["Client-wise Report", "Performance, value, and balances by company.", FileChartColumn], ["Project Category Report", "Project value and completion by category.", PieChart], ["Quotation Conversion", "Approval pipeline and conversion trends.", BarChart3]] as const;
export default function ReportsPage() { return <><PageHeader title="Reports" description="Analyze business performance across every workflow." actions={<><input className="select" type="date" /><input className="select" type="date" /><button className="button button--primary">Apply Filters</button></>} /><section className="report-grid">{reports.map(([title, description, Icon]) => <article className="export-card card" key={title}><div className="export-card__icon"><Icon size={20} /></div><h2>{title}</h2><p>{description}</p><footer><span>Live data</span><button className="button">Open Report</button></footer></article>)}</section></>; }
